import React, { useState, useRef } from "react";
import "./BloodBankPage.css";

const BloodBankPage = () => {
  const [search, setSearch] = useState("");
  const [showSuggestions, setShowSuggestions] = useState(false);
  const cardRefs = useRef({});
  const [centers] = useState([
    { id: 1, name: "Apollo Blood Bank", location: "Hyderabad", available: true, bloodTypes: ["A+", "O+", "B+"] },
    { id: 2, name: "Red Cross Blood Center", location: "Vijayawada", available: false, bloodTypes: ["A-", "AB+"] },
    { id: 3, name: "Care Hospitals Blood Bank", location: "Visakhapatnam", available: true, bloodTypes: ["O-", "B+"] },
    { id: 4, name: "NIMS Blood Bank", location: "Guntur", available: false, bloodTypes: ["AB-", "B-"] },
    { id: 5, name: "Medico Blood Center", location: "Tirupati", available: true, bloodTypes: ["A+", "AB+", "O+"] },
  ]);

  const filteredCenters = centers.filter(
    (center) =>
      center.name.toLowerCase().includes(search.toLowerCase()) ||
      center.location.toLowerCase().includes(search.toLowerCase()) ||
      center.bloodTypes.some((type) => type.toLowerCase().includes(search.toLowerCase()))
  );

  // 🩸 Build suggestion list dynamically
  const suggestions = centers.flatMap((center) => [
    center.name,
    center.location,
    ...center.bloodTypes,
  ]).filter(
    (item, index, self) =>
      item.toLowerCase().includes(search.toLowerCase()) &&
      self.indexOf(item) === index
  );

  // 🧭 When clicking a suggestion
  const handleSuggestionClick = (suggestion) => {
    setSearch(suggestion);
    setShowSuggestions(false);
    const match = centers.find(
      (c) =>
        c.name.toLowerCase().includes(suggestion.toLowerCase()) ||
        c.location.toLowerCase().includes(suggestion.toLowerCase()) ||
        c.bloodTypes.some((t) => t.toLowerCase().includes(suggestion.toLowerCase()))
    );
    if (match && cardRefs.current[match.id]) {
      cardRefs.current[match.id].scrollIntoView({ behavior: "smooth", block: "center" });
    }
  };

  return (
    <div className="bloodbank-container">
      <h2>Available Blood Banks</h2>

      {/* 🔍 Search bar with suggestions */}
      <div className="search-container">
        <input
          type="text"
          placeholder="Search by blood type, name or location..."
          value={search}
          onChange={(e) => {
            setSearch(e.target.value);
            setShowSuggestions(true);
          }}
          onBlur={() => setTimeout(() => setShowSuggestions(false), 150)} // small delay so click works
          className="search-input"
        />
        <button className="search-btn">Search</button>

        {showSuggestions && search && (
          <ul className="suggestion-box">
            {suggestions.length > 0 ? (
              suggestions.map((item, idx) => (
                <li key={idx} onClick={() => handleSuggestionClick(item)}>
                  {item}
                </li>
              ))
            ) : (
              <li className="no-suggestion">No match found</li>
            )}
          </ul>
        )}
      </div>

      {/* 🏥 Results */}
      <div className="bloodbank-list">
        {filteredCenters.length > 0 ? (
          filteredCenters.map((center) => (
            <div
              key={center.id}
              ref={(el) => (cardRefs.current[center.id] = el)}
              className={`bloodbank-card ${center.available ? "available" : "not-available"}`}
            >
              <h3>{center.name}</h3>
              <p>{center.location}</p>
              <p>
                <strong>Blood Types:</strong> {center.bloodTypes.join(", ")}
              </p>
              <span className="status">
                {center.available ? "✅ Available" : "❌ Not Available"}
              </span>
            </div>
          ))
        ) : (
          <p className="no-results">No matching results found.</p>
        )}
      </div>
    </div>
  );
};

export default BloodBankPage;
